class Solution:
    def canConvertString(self, s: str, t: str, k: int) -> bool:
        if len(s) != len(t):
            return False

        counts = [0] * 26

        for a, b in zip(s, t):
            d = (ord(b) - ord(a)) % 26
            if d != 0:
                counts[d] += 1

        for r in range(26):
            if counts[r] == 0:
                continue
            if r > k:
                return False
            max_m = (k - r) // 26 + 1
            if counts[r] > max_m:
                return False

        return True

